final:
module top_module(
    input clk,
    input rst_n,
    input enable,
    output reg VPWR,
    output reg VGND
);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or negedge rst_n or posedge dbg_halt) begin
    if (!rst_n) begin
        VPWR <= 0;
        VGND <= 0;
    end else if (enable) begin
        VPWR <= 1;
        VGND <= 0;
    end else begin
        VPWR <= 0;
        VGND <= 0;
    end
end

endmodule
